import numpy as np

class Tensor:
    def __init__(self, value, requires_grad=False):
        self.value = np.array(value)
        self.requires_grad = requires_grad
        self.grad = None

    def __add__(self, other):
        if not isinstance(other, Tensor):
            other = Tensor(other)
        result = Tensor(self.value + other.value, requires_grad=self.requires_grad or other.requires_grad)
        if result.requires_grad:
            result.grad = np.zeros_like(result.value)
        return result

    def __mul__(self, other):
        if not isinstance(other, Tensor):
            other = Tensor(other)
        result = Tensor(self.value * other.value, requires_grad=self.requires_grad or other.requires_grad)
        if result.requires_grad:
            result.grad = np.zeros_like(result.value)
        return result

    def backward(self, grad=1):
        if not self.requires_grad:
            return
        self.grad += grad * self.value
        if self.requires_grad:
            self.value.backward(grad * self.grad)

    def backward_value(self):
        if self.grad is None:
            return 1
        return self.grad / self.value

